from hatchet_sdk import Hatchet, Context, UserEventCondition, SleepCondition
from datetime import timedelta

hatchet = Hatchet()

@hatchet.workflow(name="OrderWorkflow")
class OrderWorkflow:
    @hatchet.step()
    async def process_order(self, ctx: Context):
        # Wait for either user confirmation or a 5-minute timeout
        result = await ctx.aio_wait_for(
            UserEventCondition(event_key="user:confirm"),
            SleepCondition(timedelta(minutes=5))
        )

        # result is the condition that was met
        if isinstance(result, UserEventCondition):
            return {"status": "confirmed"}

        return {"status": "cancelled"}

